(function(){
  var questions = [{"type":"mcq","html":"Variables store values for later. This variable stores text because the value is inside quote marks:<br><span class=\"green-keyword\">name</span> = <span class=\"code-string\">\"Ryan\"</span><br>What does this line do?","correct":"Stores a string","options":["Stores a string","Stores a number","Prints a value"],"right":"Quoted text is a string.","wrong":"Quotes around Ryan make it a string value stored in name."},{"type":"text","html":"Create a variable called <span class=\"green-keyword\">score</span> and store the number <span class=\"green-keyword\">100</span>. Numbers are not written inside quote marks.","correct":"score = 100","pattern":"^\\s*score\\s*=\\s*100\\s*$","right":"Numbers are stored without quotes.","wrong":"Use the variable name, then =, then the number: score = 100."},{"type":"mcq","html":"Look at this assignment:<br><span class=\"green-keyword\">age</span> = 15<br>The value is a whole number and it is not inside quote marks. What kind of variable value is being stored?","correct":"Number variable","options":["String variable","Number variable","Comment"],"right":"15 is a number because it has no quotes.","wrong":"No quotes means this is a numeric value, not text."},{"type":"text","html":"Create a variable called <span class=\"green-keyword\">city</span> and store <span class=\"green-keyword\">London</span> as text. Because London is text, it must be inside quote marks.","correct":"city = \"London\"","pattern":"^\\s*city\\s*=\\s*[\"']London[\"']\\s*$","right":"Text values need quotes.","wrong":"Use city = \"London\" with London inside quotes."},{"type":"mcq","html":"A variable name without quotes means Python uses the stored value. Read both lines:<br><span class=\"green-keyword\">name</span> = <span class=\"code-string\">\"Ryan\"</span><br><span class=\"code-func\">print</span>(<span class=\"green-keyword\">name</span>)<br>What exact output appears?","correct":"Ryan","options":["Ryan","name","\"Ryan\""],"right":"print(name) outputs the stored value.","wrong":"No quotes around name means Python uses the variable value."},{"type":"text","html":"Write one Python line to print the value stored in a variable called <span class=\"green-keyword\">name</span>. You should use the variable name without quote marks, otherwise Python would print the word name.","correct":"print(name)","pattern":"^\\s*print\\s*\\(\\s*name\\s*\\)\\s*$","right":"Use the variable name without quotes.","wrong":"Use print(name), not print(\"name\")."},{"type":"mcq","html":"A comma inside print can join a text label with a variable value. Read this line:<br><span class=\"code-func\">print</span>(<span class=\"code-string\">\"Name:\"</span>, <span class=\"green-keyword\">name</span>)<br>What is this line doing?","correct":"Prints a message and a variable","options":["Prints a message and a variable","Creates a variable","Starts a comment"],"right":"The comma separates text from the variable.","wrong":"This print statement combines a text label and a variable value."},{"type":"text","html":"Write a Python comment that explains you are creating a score variable. It must start with <span class=\"code-comment\">#</span> and include the ideas <span class=\"green-keyword\">score</span> and <span class=\"green-keyword\">variable</span>.","correct":"# create score variable","pattern":"^\\s*#.*\\b(score|variable)\\b.*\\b(score|variable)\\b.*$","right":"A useful comment starts with # and mentions score/variable.","wrong":"Start with # and mention the score variable."},{"type":"mcq","html":"Quote marks change the meaning of print. This line has quote marks around score:<br><span class=\"code-func\">print</span>(<span class=\"code-string\">\"score\"</span>)<br>What exact output appears?","correct":"score","options":["score","100","The value of score"],"right":"Quotes make Python print the word.","wrong":"Quoted text is printed literally, so this prints score, not the variable value."},{"type":"text","html":"Store the text <span class=\"green-keyword\">Coding</span> in a variable called <span class=\"green-keyword\">hobby</span>. The variable name should be on the left of = and the text value should be in quote marks.","correct":"hobby = \"Coding\"","pattern":"^\\s*hobby\\s*=\\s*[\"']Coding[\"']\\s*$","right":"String values need quotes.","wrong":"Use hobby = \"Coding\" with Coding inside quotes."}];
  var helpSlides = [{"title":"Variables store values","body":"<p>A variable is a named box for a value. Use <code class=\"bg-gray-100 px-1 rounded\">=</code> to store a value: <code>score = 100</code>.</p><p class=\"mt-2\">The variable name goes on the left. The value goes on the right.</p>"},{"title":"Strings and numbers","body":"<p>Text values are called <strong>strings</strong> and need quote marks: <code>city = \"London\"</code>.</p><p class=\"mt-2\">Numbers do not need quote marks: <code>age = 15</code>. If you put a number in quotes, Python treats it as text.</p>"},{"title":"Printing variables","body":"<p><code>print(name)</code> prints the value stored in the variable <code>name</code>. <code>print(\"name\")</code> prints the word <strong>name</strong>.</p><p class=\"mt-2\">To print a message and a variable, separate them with a comma: <code>print(\"Name:\", name)</code>.</p>"},{"title":"Comments","body":"<p>Comments start with <code>#</code> and explain your code. For example, <code># create score variable</code> is a comment because it starts with #.</p>"}];
  var idx=0, score=0, answered=false, results=[];
  var modal=document.getElementById('input-dna-help-modal');
  var helpTitle=document.getElementById('input-dna-help-title');
  var helpBody=document.getElementById('input-dna-help-body');
  var helpPager=document.getElementById('input-dna-help-pager');
  var helpPrev=document.getElementById('input-dna-help-prev');
  var helpNext=document.getElementById('input-dna-help-next');
  var helpIdx=0;
  function renderSlide(){
    var slide=helpSlides[helpIdx];
    helpTitle.textContent=slide.title;
    helpBody.innerHTML=slide.body;
    helpPager.textContent=(helpIdx+1)+' / '+helpSlides.length;
    helpPrev.disabled=helpIdx===0;
    helpNext.textContent=helpIdx===helpSlides.length-1?'Close':'Next';
  }
  document.getElementById('input-dna-help-btn').onclick=function(){ helpIdx=0; renderSlide(); modal.classList.remove('hidden'); };
  document.getElementById('input-dna-help-close').onclick=function(){ modal.classList.add('hidden'); };
  helpPrev.onclick=function(){ if(helpIdx>0){ helpIdx--; renderSlide(); } };
  helpNext.onclick=function(){ if(helpIdx<helpSlides.length-1){ helpIdx++; renderSlide(); } else { modal.classList.add('hidden'); } };
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.classList.add('hidden'); });

  var qEl=document.getElementById('input-dna-q');
  var optEl=document.getElementById('input-dna-opts');
  var ansWrap=document.getElementById('input-dna-answer-wrap');
  var fbEl=document.getElementById('input-dna-fb');
  var progEl=document.getElementById('input-dna-prog');
  var scoreEl=document.getElementById('input-dna-score');

  function normalize(s){ return String(s).trim().replace(/[??]/g,'"').replace(/[??]/g,"'"); }
  function esc(str){ return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  function checkText(q, raw){
    var val=normalize(raw);
    if(q.pattern) return new RegExp(q.pattern,'i').test(val);
    if(q.answers) return q.answers.some(function(a){ return normalize(a).toLowerCase()===val.toLowerCase(); });
    return normalize(q.correct).toLowerCase()===val.toLowerCase();
  }
  function show(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx]; answered=false;
    progEl.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML='<span class="ex-code">'+q.html+'</span>';
    optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; fbEl.className='ex-feedback';
    if(q.type==='text') renderText(q); else renderMcq(q);
  }
  function renderMcq(q){
    q.options.forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        if(answered) return; answered=true;
        optEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var ok=o===q.correct;
        results.push({q:q, wasCorrect:ok, chosen:o});
        if(ok){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
        else { btn.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. The answer is: '+q.correct; setTimeout(function(){ idx++; show(); }, 1800); }
      };
      optEl.appendChild(btn);
    });
  }
  function renderText(q){
    ansWrap.innerHTML='<input id="input-dna-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your answer here"/><button id="input-dna-check" class="ex-btn" style="margin-top:8px">Check</button>';
    var input=document.getElementById('input-dna-answer');
    var btn=document.getElementById('input-dna-check');
    function submit(){
      if(answered) return;
      var val=input.value;
      if(!val.trim()){ fbEl.className='ex-feedback hint'; fbEl.textContent='Type your answer first.'; return; }
      answered=true;
      input.disabled=true; btn.disabled=true;
      var ok=checkText(q,val);
      results.push({q:q, wasCorrect:ok, chosen:val});
      if(ok){ input.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
      else { input.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. Expected: '+q.correct; setTimeout(function(){ idx++; show(); }, 2200); }
    }
    btn.onclick=submit;
    input.onkeydown=function(e){ if(e.key==='Enter') submit(); };
    input.focus();
  }
  function finish(){
    var pct=Math.round(score/questions.length*100);
    qEl.innerHTML=''; optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; progEl.textContent='Complete'; scoreEl.textContent='';
    var resultsEl=document.getElementById('input-dna-results'); resultsEl.classList.remove('hidden');
    var msg=pct===100?'Full marks. You are ready to build on last lesson.':pct>=70?'Good work overall. Review anything you missed below.':'A few areas to revisit before moving on.';
    var html='<div class="ex-box"><p style="font-family:sans-serif;font-size:0.95rem;font-weight:600;color:#cdd6f4;margin-bottom:4px">'+score+'/'+questions.length+' - '+pct+'%</p><p style="font-family:sans-serif;font-size:0.85rem;color:#a6adc8;margin-bottom:16px">'+msg+'</p>';
    results.forEach(function(r){
      html+='<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;padding:8px 10px;background:'+(r.wasCorrect?'#1a2f20':'#2a1a1a')+';border:1px solid '+(r.wasCorrect?'#2d4a35':'#4a2a2a')+';border-radius:6px">';
      html+='<span style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+';font-size:1rem;flex-shrink:0;margin-top:1px">'+(r.wasCorrect?'&#10003;':'&#10007;')+'</span>';
      html+='<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
      html+='<p style="font-family:sans-serif;font-size:0.78rem;color:#a6adc8;margin:0 0 3px 0">Your answer: <strong style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+'">'+esc(r.chosen)+'</strong> - expected: <strong style="color:#a6e3a1">'+esc(r.q.correct)+'</strong></p>';
      html+='<p style="font-family:sans-serif;font-size:0.8rem;color:#bac2de;margin:0">'+(r.wasCorrect?r.q.right:(r.q.wrong||r.q.right))+'</p></div></div>';
    });
    html+='</div>'; resultsEl.innerHTML=html;
    window.__markStepComplete && window.__markStepComplete();
  }
  show();
})();

