he user for their <span class=\"green-keyword\">school</span> and store it</span>","correctCode":"school = input(\"Enter school\")","triggerConsole":true,"optionsRaw":["school = input(\"Enter school\")","school = input(\"Enter school\"","input(\"Enter school\")","school = print(\"Enter school\")"]}];
  var idx=0, score=0;
