(function(){
  var examData = [{"type":"mcq","prompt":"Which correctly asks the user for their name and stores it?","codeHtml":"","correct":"name = input(\"Enter your name\")","options":["name = input(\"Enter your name\")","name = print(\"Enter your name\")","input(\"Enter your name\")","name = input(\"Enter your name\""],"explanation":"input() reads from the user and must be assigned to a variable to store it."},{"type":"mcq","prompt":"Which correctly asks the user for their age as a number?","codeHtml":"","correct":"age = int(input(\"Enter your age\"))","options":["age = int(input(\"Enter your age\"))","age = input(\"Enter your age\")","age = int(input(\"Enter your age\")","int(input(\"Enter your age\"))"],"explanation":"input() always returns a string - use int() to convert it to a number."},{"type":"mcq","prompt":"Which data type is this value: <span class=\"green-keyword\">\"Hello\"</span>","codeHtml":"","correct":"String","options":["String","Integer","Float","Boolean"],"explanation":"Any value wrapped in quotes is a String."},{"type":"mcq","prompt":"Which data type is this value: <span class=\"green-keyword\">3.14</span>","codeHtml":"","correct":"Float","options":["String","Integer","Float","Boolean"],"explanation":"A number with a decimal point is a Float."},{"type":"mcq","prompt":"Which code correctly converts the variable <span class=\"green-keyword\">score</span> to an integer?","codeHtml":"","correct":"int(score)","options":["int(score)","integer(score)","score.int()","str(score)"],"explanation":"Use int() to convert a value to an integer."},{"type":"mcq","prompt":"What data type does input() always return?","codeHtml":"","correct":"String","options":["String","Integer","Float","Boolean"],"explanation":"input() always returns a String, even if the user types a number."},{"type":"text_var","prompt":"Ask the user for their <span class=\"green-keyword\">name</span> and store it.","targetVar":"name","isString":true,"isInput":true,"explanation":"Format: name = input(\"Enter your name\")"},{"type":"text_var","prompt":"Ask the user for their <span class=\"green-keyword\">age</span> and store it as a number.","targetVar":"age","isString":false,"isInput":true,"explanation":"Format: age = int(input(\"Enter your age\"))"},{"type":"text_var","prompt":"Convert the variable <span class=\"green-keyword\">score</span> to a <span class=\"green-keyword\">float</span>.","targetVar":"score","isString":false,"explanation":"Format: float(score)"},{"type":"extended_run","prompt":"Write a script that:\n1. Asks the user for their <b>name</b> (string)\n2. Asks the user for their <b>age</b> (number)\n3. Asks the user for their <b>city</b> (string)\n4. Prints each one with an appropriate message.","explanation":"Format:\nname = input(\"Enter your name\")\nage = int(input(\"Enter your age\"))\ncity = input(\"Enter your city\")\nprint(\"Name:\", name)\nprint(\"Age:\", age)\nprint(\"City:\", city)","expectedVars":[{"name":"name","type":"string","strict":false},{"name":"age","type":"number","strict":false},{"name":"city","type":"string","strict":false}],"expectedOutput":[{"containsVar":"name","hasMessage":true},{"containsVar":"age","hasMessage":true},{"containsVar":"city","hasMessage":true}]}];
  var idx=0, score=0;
  var prog=document.getElementById('s3-prog');
  var scoreEl=document.getElementById('s3-score');
  var wrap=document.getElementById('s3-wrap');
  function rx(pattern, value){ return new RegExp(pattern,'im').test(value); }
  function inputAssign(code, name, isNumber){
    var prompt = "(?:\"[^\"\\n]+\"|'[^'\\n]+')";
    var p = isNumber
      ? name + "\\s*=\\s*int\\s*\\(\\s*input\\s*\\(\\s*" + prompt + "\\s*\\)\\s*\\)"
      : name + "\\s*=\\s*input\\s*\\(\\s*" + prompt + "\\s*\\)";
    return rx(p, code);
  }
  function hasPrintVar(code, name){ return rx('print\\s*\\([^)]*\\b'+name+'\\b[^)]*\\)', code); }
  function render(){
    if(idx>=examData.length){ finish(); return; }
    var q=examData[idx];
    prog.textContent='Question '+(idx+1)+' of '+examData.length;
    scoreEl.textContent='Score: '+score;
    if(q.type==='mcq') renderMcq(q); else renderText(q);
  }
  function renderMcq(q){
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:6px">'+q.prompt+'</div>';
    if(q.codeHtml) html+='<div class="ex-code" style="margin-bottom:10px">'+q.codeHtml+'</div>';
    html+='<div class="ex-options" id="s3-opts"></div><div class="ex-feedback" id="s3-fb"></div><div class="ex-explanation" id="s3-exp" style="display:none"></div></div>';
    wrap.innerHTML=html;
    q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(opt){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=opt;
      btn.onclick=function(){
        document.querySelectorAll('#s3-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var fb=document.getElementById('s3-fb'), exp=document.getElementById('s3-exp');
        exp.textContent=q.explanation||''; exp.style.display=exp.textContent?'block':'none';
        if(opt===q.correct){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1000); }
        else { btn.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; setTimeout(function(){idx++;render();},2200); }
      };
      document.getElementById('s3-opts').appendChild(btn);
    });
  }
  function renderText(q){
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:8px">'+q.prompt.replace(/\n/g,'<br>')+'</div>';
    html+='<textarea id="s3-ta" class="ex-textarea" rows="'+(q.type==='extended_run'?10:4)+'" spellcheck="false" placeholder="Write your code here"></textarea>';
    html+='<button id="s3-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="s3-fb"></div><div class="ex-explanation" id="s3-exp" style="display:none">'+(q.explanation||'')+'</div></div>';
    wrap.innerHTML=html;
    document.getElementById('s3-check').onclick=function(){ checkText(q); };
    document.getElementById('s3-ta').focus();
  }
  function checkText(q){
    var code=document.getElementById('s3-ta').value.trim();
    var fb=document.getElementById('s3-fb'), exp=document.getElementById('s3-exp');
    exp.style.display='block';
    if(!code){ fb.className='ex-feedback hint'; fb.textContent='Write your answer first.'; return; }
    var ok=false;
    if(q.type==='text_var' && q.isInput) ok=inputAssign(code,q.targetVar,!q.isString);
    else if(q.type==='text_var' && q.targetVar==='score') ok=/^float\s*\(\s*score\s*\)$/i.test(code);
    else if(q.type==='extended_run') ok=inputAssign(code,'name',false) && inputAssign(code,'age',true) && inputAssign(code,'city',false) && hasPrintVar(code,'name') && hasPrintVar(code,'age') && hasPrintVar(code,'city');
    if(ok){ score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1200); }
    else { fb.className='ex-feedback err'; fb.textContent='Not quite. Use the scaffold shown below.'; }
  }
  function finish(){
    var pct=Math.round(score/examData.length*100);
    var grade=pct>=90?'Outstanding':pct>=70?'Secure':pct>=50?'Developing':'Needs more practice';
    wrap.innerHTML='<div class="ex-box"><p style="font-family:sans-serif;font-size:1rem;font-weight:600;color:#cdd6f4;margin-bottom:6px">Stage 3 complete: '+score+'/'+examData.length+' ('+pct+'%)</p><p style="font-family:sans-serif;font-size:0.9rem;color:#a6adc8;margin-bottom:10px">Grade: '+grade+'</p><p style="font-family:sans-serif;font-size:0.85rem;color:#bac2de">You have practised input(), data types, type conversion, and printing input values with messages.</p></div>';
    prog.textContent='Complete'; scoreEl.textContent='';
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

steps.css:
.ex-box{background:#1e1e2e;border:1px solid #313244;border-radius:10px;padding:16px 20px;margin-bottom:14px}
.ex-prompt{font-family:sans-serif;font-size:0.85rem;color:#cdd6f4;margin-bottom:10px}
.ex-code{color:#cdd6f4;font-size:0.95rem;line-height:1.7;letter-spacing:0.01em;font-family:'Courier New',monospace;display:block}
.code-func{color:#cba6f7}
.code-string{color:#a6e3a1}
.code-comment{color:#94e2d5;font-style:italic}
.code-error{color:#f38ba8}
.green-keyword{color:#a6e3a1;font-weight:600}
.ex-options{display:block;margin-top:10px}
.ex-opt{display:block;width:100%;background:#313244;color:#cdd6f4;border:1px solid #45475a;border-radius:6px;padding:10px 14px;font-family:'Courier New',monospace;font-size:0.9rem;cursor:pointer;text-align:left;margin-bottom:6px;box-sizing:border-box;line-height:1.4}
.ex-opt:last-child{margin-bottom:0}
.ex-opt:hover:not([disabled]){background:#45475a;border-color:#94e2d5}
.ex-opt.correct{background:#1a3328!important;border-color:#a6e3a1!important;color:#a6e3a1!important}
.ex-opt.wrong{background:#351c1c!important;border-color:#f38ba8!important;color:#f38ba8!important}
.ex-opt[disabled]{cursor:default}
.ex-feedback{margin-top:10px;font-size:0.85rem;min-height:20px;font-family:sans-serif;line-height:1.4}
.ex-feedback.ok{color:#a6e3a1}
.ex-feedback.err{color:#f38ba8}
.ex-feedback.hint{color:#f9e2af}
.ex-progress{font-size:0.8rem;color:#585b70;margin-bottom:4px;font-family:sans-serif}
.ex-score{font-size:0.85rem;font-weight:600;color:#cba6f7;margin-bottom:10px;font-family:sans-serif}
.ex-label{font-family:sans-serif;font-size:0.82rem;color:#89b4fa;margin-bottom:10px;display:block}
.ex-explanation{background:#252535;border-left:3px solid #89b4fa;padding:8px 12px;margin-top:10px;font-size:0.82rem;color:#bac2de;font-family:sans-serif;border-radius:0 6px 6px 0;line-height:1.5}

.ex-input,.ex-textarea{width:100%;background:#11111b;color:#cdd6f4;border:1px solid #45475a;border-radius:6px;padding:10px 12px;font-family:'Courier New',monospace;font-size:0.9rem;box-sizing:border-box;line-height:1.45}
.ex-input:focus,.ex-textarea:focus{outline:none;border-color:#89b4fa;box-shadow:0 0 0 2px rgba(137,180,250,0.25)}
.ex-input.correct,.ex-textarea.correct{border-color:#a6e3a1;background:#14251d}
.ex-input.wrong,.ex-textarea.wrong{border-color:#f38ba8;background:#281616}
.ex-btn{display:inline-block;background:#2563eb;color:white;border:0;border-radius:6px;padding:8px 14px;font-family:sans-serif;font-size:0.85rem;font-weight:600;cursor:pointer}
.ex-btn:hover:not([disabled]){background:#1d4ed8}
.ex-btn[disabled]{opacity:0.55;cursor:default}

steps.js:
(function(){
  var mcqPool = [{"prompt":"Choose the correct input code:","html":"<span style=\"font-size:0.9rem\">Ask for a <span class=\"green-keyword\">name</span> and store it.</span>","correct":"name = input(\"Enter name\")","options":["name = input(\"Enter name\")","name = print(\"Enter name\")","input(\"Enter name\")","name = input(\"Enter name\""]},{"prompt":"Choose the correct number input:","html":"<span style=\"font-size:0.9rem\">Ask for <span class=\"green-keyword\">age</span> as a number.</span>","correct":"age = int(input(\"Enter age\"))","options":["age = int(input(\"Enter age\"))","age = input(\"Enter age\")","int(input(\"Enter age\"))","age = int(input(\"Enter age\")"]},{"prompt":"Choose the data type:","html":"<span style=\"font-size:0.9rem\">Which data type is <span class=\"green-keyword\">3.14</span>?</span>","correct":"Float","options":["Integer","Float","String","Boolean"]},{"prompt":"Choose the data type:","html":"<span style=\"font-size:0.9rem\">Which data type is <span class=\"green-keyword\">\"42\"</span>?</span>","correct":"String","options":["Integer","Float","String","Boolean"]}];
  var textPool = [{"label":"Write input code:","html":"<span style=\"font-size:0.9rem\">Ask for <span class=\"green-keyword\">city</span> and store it.</span>","pattern":"city\\s*=\\s*input\\s*\\(\\s*(?:\"[^\"]+\"|'[^']+')\\s*\\)","hint":"city = input(\"Enter city\")","rows":1},{"label":"Write number input code:","html":"<span style=\"font-size:0.9rem\">Ask for <span class=\"green-keyword\">score</span> as a number.</span>","pattern":"score\\s*=\\s*int\\s*\\(\\s*input\\s*\\(\\s*(?:\"[^\"]+\"|'[^']+')\\s*\\)\\s*\\)","hint":"score = int(input(\"Enter score\"))","rows":1},{"label":"Convert the type:","html":"<span style=\"font-size:0.9rem\">Convert <span class=\"green-keyword\">height</span> to a float.</span>","pattern":"float\\s*\\(\\s*height\\s*\\)","hint":"float(height)","rows":1},{"label":"Input and print:","html":"<span style=\"font-size:0.9rem\">Ask for <span class=\"green-keyword\">food</span>, then print it with a message.</span>","pattern":"food\\s*=\\s*input\\s*\\(\\s*(?:\"[^\"]+\"|'[^']+')\\s*\\)\\s*[\\r\\n]+\\s*print\\s*\\([^)]*\\bfood\\b[^)]*\\)","hint":"food = input(\"Food?\")\nprint(\"I like\", food)","rows":4}];
  var streak=0, best=parseInt(localStorage.getItem("pylearn_input_best")||'0',10);
  document.getElementById('input-ep-best').textContent=best;
  function rand(a){ return a[Math.floor(Math.random()*a.length)]; }
  function correct(){ streak++; if(streak>best){ best=streak; localStorage.setItem("pylearn_input_best", best); document.getElementById('input-ep-best').textContent=best; } document.getElementById('input-ep-streak').textContent=streak; if(streak>=5)window.__markStepComplete&&window.__markStepComplete(); }
  function wrong(){ streak=0; document.getElementById('input-ep-streak').textContent=streak; }
  function next(){ Math.random()<0.5 ? showMcq(rand(mcqPool)) : showText(rand(textPool)); }
  function showMcq(q){
    var wrap=document.getElementById('input-ep-q');
    wrap.innerHTML='<div class="ex-prompt">'+q.prompt+'</div><div class="ex-code" style="margin-bottom:10px">'+q.html+'</div><div class="ex-options" id="input-ep-opts"></div><div class="ex-feedback" id="input-ep-fb"></div>';
    q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        document.querySelectorAll('#input-ep-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct)b.classList.add('correct'); });
        var fb=document.getElementById('input-ep-fb');
        if(o===q.correct){ btn.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); }
        else { btn.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; }
      };
      document.getElementById('input-ep-opts').appendChild(btn);
    });
  }
  function showText(q){
    var wrap=document.getElementById('input-ep-q');
    var field=q.rows>1?'<textarea id="input-ep-answer" class="ex-textarea" rows="'+q.rows+'" spellcheck="false" placeholder="Write your code here"></textarea>':'<input id="input-ep-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your code here"/>';
    wrap.innerHTML='<div class="ex-prompt">'+q.label+'</div><div class="ex-code" style="margin-bottom:10px">'+q.html+'</div>'+field+'<button id="input-ep-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="input-ep-fb"></div><div class="ex-explanation" id="input-ep-hint" style="display:none"></div>';
    document.getElementById('input-ep-check').onclick=function(){
      var input=document.getElementById('input-ep-answer'); var val=input.value.trim(); var fb=document.getElementById('input-ep-fb'); var hint=document.getElementById('input-ep-hint');
      if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; hint.textContent=q.hint; hint.style.display='block'; return; }
      if(new RegExp('^'+q.pattern+'$','i').test(val)){ input.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); }
      else { input.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax.'; hint.textContent=q.hint; hint.style.display='block'; }
    };
    document.getElementById('input-ep-answer').focus();
  }
  next();
})();
